// Load all configuration from variables
const config = {
  // Cost Configuration
  cost_uzs: {
    agent_hourly_rate: parseInt($vars.AGENT_HOURLY_RATE) || 50000,
    manual_ticket_cost: parseInt($vars.MANUAL_TICKET_COST) || 12500,
    ai_processing_cost: parseInt($vars.AI_PROCESSING_COST) || 2500,
    savings_per_ticket: parseInt($vars.SAVINGS_PER_TICKET) || 10000,
    tickets_per_month: parseInt($vars.TICKETS_PER_MONTH) || 1000
  },

  // AI Configuration
  ai_config: {
    model: "openai/gpt-4o-mini",
    timeout_ms: 6000,
    retry_count: 3,
    confidence_threshold: 0.7
  },

  // SLA Configuration
  uzbekistan_sla: {
    timezone: 'Asia/Tashkent',
    business_hours: { start: 9, end: 18, days: [1, 2, 3, 4, 5] },
    thresholds_ms: { critical: 1800000, high: 7200000, medium: 28800000, low: 86400000 },
    after_hours_multiplier: 1.5
  },

  // System Configuration
  system_config: {
    workflow_version: 'Revenant_v20_HYBRID_ENTERPRISE',
    max_tickets_per_minute: 100,
    audit_log_enabled: true,
    telemetry_enabled: true,
    // ✅ ADDED: Initialize memory retrieval failure counter
    memory_retrieval_failures: 0
  }
};

// Validate configuration
const validation = {
  has_cost_config: !!config.cost_uzs,
  has_ai_config: !!config.ai_config,
  variables_loaded: {
    AGENT_HOURLY_RATE: !!$vars.AGENT_HOURLY_RATE,
    MANUAL_TICKET_COST: !!$vars.MANUAL_TICKET_COST,
    AI_PROCESSING_COST: !!$vars.AI_PROCESSING_COST,
    SAVINGS_PER_TICKET: !!$vars.SAVINGS_PER_TICKET,
    TICKETS_PER_MONTH: !!$vars.TICKETS_PER_MONTH
  }
};

const outputItem = {
  json: {
    config: config,
    config_validation: validation,
    loaded_at: new Date().toISOString(),
    node_count: Object.keys($node || {}).length
  }
};

// ✅ EXECUTION IDENTITY - ADDED AT END FOR MERGE DETERMINISM
outputItem.json.trace_id = $execution.id;

return [outputItem];

const item = $input.first();
const ct = item.json.canonical_ticket;

// Phase 0 Core Validation - HARDENED FOR TYPE SAFETY
const errors = [];

// 1. REQUIRED: Trace ID must exist and be valid
if (!ct.trace_id) {
  errors.push('MISSING_TRACE_ID');
} else {
  // Convert to string safely for validation
  const traceIdStr = String(ct.trace_id);
  if (traceIdStr.trim().length === 0) {
    errors.push('EMPTY_TRACE_ID');
  }
}

// 2. REQUIRED: Subject must exist and be valid length
if (!ct.subject) {
  errors.push('MISSING_SUBJECT');
} else {
  const subjectStr = String(ct.subject);
  if (subjectStr.trim().length === 0) {
    errors.push('EMPTY_SUBJECT');
  } else if (subjectStr.trim().length > 500) {
    errors.push('SUBJECT_TOO_LONG');
  }
}

// 3. REQUIRED: Valid email format
if (!ct.customer_email) {
  errors.push('MISSING_CUSTOMER_EMAIL');
} else {
  const emailStr = String(ct.customer_email);
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailStr)) {
    errors.push('INVALID_CUSTOMER_EMAIL_FORMAT');
  }
}

// 4. SANITY: workflow_error shouldn't exist yet
if (ct.workflow_error) {
  errors.push('PREMATURE_WORKFLOW_ERROR');
}

// 5. ✅ CORRECTED: language_analysis is NOT required at this stage
//    This validation was premature - removing requirement

// 6. ✅ CORRECTED: rule_engine is NOT required at this stage  
//    This validation was premature - removing requirement

// VALIDATION RESULT
if (errors.length > 0) {
  return [{
    json: {
      canonical_ticket: {
        ...ct,
        workflow_error: {
          type: 'PHASE_0_VALIDATION_FAILED',
          errors: errors,
          timestamp: new Date().toISOString(),
          trace_id: String(ct.trace_id || 'UNKNOWN'),  // Convert to string
          stage: 'phase_0_validation',
          input_sample: {
            subject: ct.subject ? String(ct.subject).substring(0, 50) : 'missing',
            email: ct.customer_email ? String(ct.customer_email) : 'missing'
          }
        },
        __validation_failed: true
      }
    }
  }];
}

// ✅ PHASE 0 COMPLETE - Continue normally
return [{
  json: {
    trace_id: String(ct.trace_id) ,
    canonical_ticket: {
      ...ct,
      // Ensure trace_id is string for downstream consistency
      trace_id: String(ct.trace_id),
      // Add Phase 0 validation timestamp
      phase_0_completed_at: new Date().toISOString(),
      phase_0_status: 'validated'
    }
  }
}];

// Input Validator & Cleaner - V16 - HARDENED
const envelope = $input.first().json;

// ARCHITECTURAL GUARD - Must have envelope structure
if (!envelope.meta || envelope.meta.stage !== 'SB0') {
  throw new Error(`ARCHITECTURAL_VIOLATION: Invalid envelope stage - expected SB0, got ${envelope.meta?.stage}`);
}

const payload = envelope.payload;

// Validate required fields exist
const requiredFields = ['subject', 'body', 'customer_email'];
const missingFields = requiredFields.filter(field => !payload?.[field]);
if (missingFields.length > 0) {
  throw new Error(`SB1_VALIDATION_FAILED: Missing payload fields: ${missingFields.join(', ')}`);
}

// Clean text function
const cleanText = (text) => {
  if (!text) return '';
  return text.toString()
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<[^>]*>/g, '')
    .replace(/[&<>"']/g, char => ({
      '&': '&amp;',
      '<': '&lt;', 
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#x27;'
    }[char]))
    .replace(/[\t\n\r]+/g, ' ')
    .trim();
};

// Extract headers from envelope (preserved in SB0 envelope)
const originalHeaders = envelope.original_headers || {};

// Build canonical ticket with SINGULARITY FLAG
const cleaned_ticket = {
  trace_id: envelope.meta.trace_id,
  subject: cleanText(payload.subject),
  body: cleanText(payload.body),
  customer_email: cleanText(payload.customer_email),
  original_subject: payload.subject,
  original_body: payload.body,
  original_customer_email: payload.customer_email,
  severity: payload.severity || 'medium',
  priority: payload.priority || 'medium',
  category: payload.category || 'technical',
  webhook_received_at: new Date().toISOString(),
  client_ip: originalHeaders['x-forwarded-for'] || 'unknown',
  user_agent: originalHeaders['user-agent'] || 'unknown',
  // ⚡ CRITICAL SINGULARITY FLAG - Prevents re-validation
  __validation_attempted: true,
  // Audit trail
  validation_stage: 'SB1',
  envelope_processed_at: envelope.meta?.timestamp || new Date().toISOString()
};

return [{
  json: {
    canonical_ticket: cleaned_ticket,
    // Preserve envelope metadata for traceability
    __envelope_metadata: {
      trace_id: envelope.meta.trace_id,
      stage: envelope.meta.stage,
      execution_mode: envelope.meta.execution_mode,
      processed_at: new Date().toISOString()
    }
  }
}];

// ⚠️ SB1 ERROR EXIT – Validation Failure Handler - TERMINAL
const item = $input.first();

// TERMINAL ERROR - Structured for webhook response
return [{
  json: {
    // Signal to Return Validation Error node that this is a terminal error
    __terminal_error: true,
    error_type: 'SB1_VALIDATION_TERMINAL',
    trace_id: item.json.meta?.trace_id || 'unknown',
    stage: 'SB1',
    http_code: 400,
    reason: 'Validation failed – terminal exit',
    timestamp: new Date().toISOString(),

    // Preserve envelope structure for audit trail
    original_envelope: {
      meta: item.json.meta,
      config: item.json.config,
      payload: item.json.payload
    }
  }
}];

// PROD Input Normalizer - Hardened V20
const item = $input.first();
const json = item.json;

// 1. CANONICAL TRACE ID - ADDED AT TOP FOR DETERMINISM
item.json.trace_id = $execution.id;

// 2. EXISTING NORMALIZATION LOGIC
if (json.subject && json.body && !json.body?.subject) {
  return [{
    json: {
      trace_id: $execution.id, // Preserve in normalized structure
      body: {
        subject: json.subject,
        body: json.body,
        customer_email: json.customer_email || null
      }
    }
  }];
}

// 3. ENSURE TRACE_ID PERSISTS IN ALL RETURN PATHS
return [{ 
  json: {
    ...json,
    trace_id: $execution.id // Force overwrite to prevent any upstream contamination
  }
}];

const item = $input.first();
const ct = item.json.canonical_ticket;
const text = (ct.subject + ' ' + ct.body).toLowerCase();

// Priority Rules for Uzum Ecosystem
const rules = [
  { 
    intent: 'access_issue', 
    regex: /\b(403|401|login|password|access|denied|portal|kabinet|kirish|parol|vaxod|dostup|forbidden)\b/, 
    severity: 'high', 
    score: 0.95 
  },
  { 
    intent: 'payment_issue', 
    regex: /\b(payment|to'lov|oplat|o'tkazma|transak|card|karta|uzcard|humo|click|payme)\b/, 
    severity: 'critical', 
    score: 0.9 
  },
  { 
    intent: 'security_alert', 
    regex: /\b(security|xavfsizlik|hacker|attack|virus|hack|fishing|vzlom)\b/, 
    severity: 'critical', 
    score: 1.0 
  },
  { 
    intent: 'network_issue', 
    regex: /\b(internet|network|tarmoq|connect|sechenie|vpn|slow|sekin|medlenno)\b/, 
    severity: 'medium', 
    score: 0.85 
  }
];

let detectedIntent = 'general_inquiry';
let detectedSeverity = ct.severity || 'medium';
let ruleConfidence = 0.5;

for (const rule of rules) {
  if (rule.regex.test(text)) {
    detectedIntent = rule.intent;
    detectedSeverity = rule.severity;
    ruleConfidence = rule.score;
    // Boost severity if it's a Merchant specific issue
    if (text.includes('merchant') || text.includes('portal') || text.includes('tadbirkor')) {
        detectedSeverity = (detectedSeverity === 'critical') ? 'critical' : 'high';
    }
    break;
  }
}

return [{
  json: {
    ...item.json,
    canonical_ticket: {
      ...ct,
      rule_engine: {
        intent: detectedIntent,
        severity: detectedSeverity,
        confidence: ruleConfidence,
        detected_at: new Date().toISOString(),
        engine_version: "2.1.0-enterprise"
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

/**
 * REVENANT ENTERPRISE: Rule-Based Severity Classifier V22
 * Logic: Multi-factor weighted heuristic engine.
 */
const item = $input.first();
const ct = item.json.canonical_ticket || item.json;
const text = (ct.subject + ' ' + ct.body).toLowerCase();
const features = ct.text_features || {};

// 1. Scoring Matrix (Enterprise Weights)
const scores = { critical: 0, high: 0, medium: 0, low: 0 };

const WEIGHTS = {
  CRITICAL_INDICATOR: 3.5,
  HIGH_INDICATOR: 2.0,
  ERROR_CODE_MATCH: 1.5,
  INTENT_ESCALATION: 2.5,
  LENGTH_PENALTY: 1.0
};

// 2. High-Fidelity Pattern Matching
const patterns = {
  critical: /\b(outage|down|breach|loss|emergency|ishlamayapti|отключен|критическая)\b/i,
  high: /\b(failed|cannot|unable|error|failed|urgent|tezda|сброс|ошибка)\b/i,
  technical_errors: /error\s+(403|500|502|503|401)|timeout|database/i
};

// 3. Execution Logic
if (patterns.critical.test(text)) scores.critical += WEIGHTS.CRITICAL_INDICATOR;
if (patterns.high.test(text)) scores.high += WEIGHTS.HIGH_INDICATOR;
if (patterns.technical_errors.test(text)) scores.high += WEIGHTS.ERROR_CODE_MATCH;

// Cross-reference Text Features
if (features.has_critical) scores.critical += 2;
if (features.has_error_code) scores.high += 1.5;

// 4. Intent-Aware Escalation (Cross-Node Intelligence)
if (ct.rule_engine?.intent === 'access_issue' && text.includes('merchant')) {
    scores.high += WEIGHTS.INTENT_ESCALATION;
}

// 5. Deterministic Severity Selection
const maxScore = Math.max(scores.critical, scores.high, scores.medium, scores.low);
let finalSeverity = 'medium';

if (scores.critical >= 3) finalSeverity = 'critical';
else if (scores.high >= 2) finalSeverity = 'high';
else if (scores.medium >= 1) finalSeverity = 'medium';
else finalSeverity = 'low';

const confidence = Math.min(0.98, 0.4 + (maxScore / 10));

return [{
  json: {
    ...item.json,
    rule_based_severity: {
      severity: finalSeverity,
      confidence: parseFloat(confidence.toFixed(2)),
      scores: scores,
      calculated_at: new Date().toISOString()
    },
    canonical_ticket: {
      ...ct,
      rule_based_severity: {
        severity: finalSeverity,
        confidence: parseFloat(confidence.toFixed(2)),
        scores: scores
      }
    }
  }
}];

// Text Feature Engineering (Deterministic) - V20
const item = $input.first();
const ct = item.json.canonical_ticket;

// Validate input has required fields
if (!ct.trace_id || !ct.subject || !ct.body) {
  throw new Error(`MISSING_REQUIRED_FIELDS: trace_id=${!!ct.trace_id}, subject=${!!ct.subject}, body=${!!ct.body}`);
}

const text = (ct.subject || '') + ' ' + (ct.body || '');
const textLower = text.toLowerCase();

// Length features
const features = {
  subject_length: ct.subject?.length || 0,
  body_length: ct.body?.length || 0,
  total_length: text.length,
  word_count: text.split(/\s+/).filter(w => w).length
};

// Keyword detection
features.has_critical = /\b(critical|emergency|outage|down|breach)\b/i.test(text);
features.has_urgent = /\b(urgent|immediate|asap|now)\b/i.test(text);
features.has_error_code = /error\s+\d+|code\s+\d+|err\s+\d+/i.test(text);
features.has_question = /\b(how|what|why|can|could|would)\b/i.test(text);

// Complexity score
features.complexity_score = (
  features.word_count * 0.1 +
  (features.has_critical ? 3 : 0) +
  (features.has_urgent ? 2 : 0) +
  (features.has_error_code ? 1 : 0)
);

// Update canonical ticket
const updatedTicket = {
  ...ct,
  text_features: features,
  data_integrity: {
    ...ct.data_integrity,
    last_modified: Date.now(),
    modification_count: (ct.data_integrity?.modification_count || 0) + 1
  }
};

return [{
  json: {
    canonical_ticket: updatedTicket
  }
}];

/**
 * REVENANT ENTERPRISE: Pre-Fusion Normalizer V22
 * Logic: Conflict resolution & provenance stabilization.
 */
const item = $input.first();
const ct = item.json.canonical_ticket;

// 1. HARD VALIDATION: Fail-Fast for Data Integrity
if (!ct.rule_engine || !ct.rule_based_severity) {
  throw new Error(`INTEGRITY_VIOLATION: Missing intelligence inputs in trace ${ct.trace_id}`);
}

// 2. CONFLICT RESOLUTION (Expert Logic)
// If rule-based severity is 'critical' but engine says 'medium', we escalate to be safe.
const engineSev = ct.rule_engine.severity;
const ruleSev = ct.rule_based_severity.severity;

const SEVERITY_RANK = { critical: 4, high: 3, medium: 2, low: 1 };

const resolvedSeverity = (SEVERITY_RANK[ruleSev] >= SEVERITY_RANK[engineSev]) 
    ? ruleSev 
    : engineSev;

// 3. CONFIDENCE AGGREGATION
const normalizedConfidence = (ct.rule_engine.confidence + ct.rule_based_severity.confidence) / 2;

// 4. ENTERPRISE CLASSIFICATION OBJECT
const classification = {
  intent: ct.rule_engine.intent,
  severity: resolvedSeverity,
  confidence: parseFloat(normalizedConfidence.toFixed(2)),
  source: "hybrid_fusion_engine_v22",
  normalized_at: new Date().toISOString(),
  // EXPLAINABLE AI: Provenance maintains the "Why"
  provenance: {
    intent_source: "rule_engine_v21",
    severity_strategy: (ruleSev !== engineSev) ? "escalated_by_rule" : "consensus",
    raw_scores: {
      engine: engineSev,
      rules: ruleSev
    }
  }
};

// 5. IMMUTABLE UPDATE
return [{
  json: {
    canonical_ticket: {
      ...ct,
      classification: classification,
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1,
        classification_normalized: true
      }
    }
  }
}];

/**
 * @file Business Impact & ROI Calculator
 * @version 2.1.0
 * @description Calculates financial impact and efficiency gains for automated ticket resolution.
 */

// 1. Constants & Default Configuration (Hardened)
const DEFAULTS = {
    COST_CONFIG: {
        agent_hourly_rate: 50000,
        manual_ticket_cost: 12500,
        ai_processing_cost: 2500,
        avg_resolution_time_mins: 15
    },
    CURRENCY: 'UZS'
};

try {
    const item = $input.first();
    const ct = item.json.canonical_ticket || {};

    // 2. Defensive Configuration Loading
    // Hierarchy: Workflow Config > Ticket Meta > Global Defaults
    const config = {
        ...DEFAULTS.COST_CONFIG,
        ...(ct.workflow_metadata?.config?.cost_uzs || {})
    };

    // 3. Extraction & Validation
    const isAutoResolved = ct.ticket_status === 'auto_resolved';
    const aiCost = Number(config.ai_processing_cost) || 0;
    const manualCost = Number(config.manual_ticket_cost) || 0;

    // 4. Core Logic: Financial Impact
    // Enterprise Standard: We calculate Gross Savings before ROI
    const grossSavings = isAutoResolved ? Math.max(0, manualCost - aiCost) : 0;

    // Prevent Division by Zero and handle ROI as a Ratio
    const roiPercentage = (isAutoResolved && aiCost > 0) 
        ? ((manualCost - aiCost) / aiCost) * 100 
        : 0;

    // 5. Build Structured Response
    return [{
        json: {
            ...item.json, // Preserve original root data
            canonical_ticket: {
                ...ct,
                business_impact: {
                    metrics: {
                        ai_cost_uzs: aiCost,
                        manual_cost_uzs: manualCost,
                        cost_saved_uzs: grossSavings,
                        roi_percent: parseFloat(roiPercentage.toFixed(2)),
                        time_saved_minutes: isAutoResolved ? config.avg_resolution_time_mins : 0
                    },
                    metadata: {
                        calculation_timestamp: new Date().toISOString(),
                        currency: DEFAULTS.CURRENCY,
                        config_source: ct.workflow_metadata?.config?.cost_uzs ? 'dynamic_override' : 'system_default',
                        version: "2.1.0"
                    }
                },
                data_integrity: {
                    ...ct.data_integrity,
                    last_modified: Date.now(),
                    modification_count: (ct.data_integrity?.modification_count || 0) + 1,
                    trace_id: ct.workflow_metadata?.trace_id || 'N/A'
                }
            }
        }
    }];

} catch (error) {
    // 6. Enterprise Error Handling
    // Instead of crashing, we return the item with an error flag for the next node to handle
    return [{
        json: {
            ...$input.first().json,
            error: {
                message: "Business Impact Calculation Failed",
                details: error.message,
                context: "impact_calculator_node"
            }
        }
    }];
}

/**
 * @file Uzbekistan SLA Engine
 * @version 2.1.0
 * @author Senior Systems Architect
 */

const item = $input.first();
const ct = item.json.canonical_ticket || {};

// 1. Immutable Time References
// Use the original webhook arrival time for SLA, not the current execution time
const referenceTime = new Date(ct.webhook_received_at || Date.now()).getTime();
const currentTime = Date.now();

// 2. Localization Logic
// We use Intl to handle Tashkent time without manual millisecond math
const tashkentTimeStr = new Intl.DateTimeFormat('en-US', {
  timeZone: 'Asia/Tashkent',
  hour12: false,
  weekday: 'long',
  year: 'numeric',
  month: 'numeric',
  day: 'numeric',
  hour: 'numeric',
  minute: 'numeric',
  second: 'numeric'
}).format(new Date(currentTime));

// Parse the formatted string to get clean components
const dayOfWeek = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Tashkent', weekday: 'long' }).format(currentTime);
const hourTJS = parseInt(new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Tashkent', hour: 'numeric', hour12: false }).format(currentTime));

// 3. Business Logic Gates
const slaConfig = ct.workflow_metadata?.config?.uzbekistan_sla || {};
const isWeekend = ['Saturday', 'Sunday'].includes(dayOfWeek);
const isBusinessHours = !isWeekend && (hourTJS >= 9 && hourTJS < 18);

// 4. Threshold & Multiplier Resolution
const severity = ct.classification?.severity || 'medium';
const baseThresholds = slaConfig.thresholds_ms || {
  critical: 1800000, 
  high: 7200000, 
  medium: 28800000, 
  low: 86400000
};

const multiplier = isBusinessHours ? 1 : (slaConfig.after_hours_multiplier || 1.5);
const resolvedThreshold = (baseThresholds[severity] || baseThresholds.medium) * multiplier;

// 5. Performance Calculation
const totalProcessingMs = currentTime - referenceTime;
const deadlineTime = referenceTime + resolvedThreshold;
const isBreached = totalProcessingMs > resolvedThreshold;

// 6. Breach Classification (Categorical Analysis)
const getBreachLevel = (ms) => {
  if (ms <= 0) return 'none';
  if (ms > 3600000) return 'critical'; // > 1 hour late
  if (ms > 900000) return 'major';    // > 15 mins late
  return 'minor';
};



return [{
  json: {
    ...item.json,
    canonical_ticket: {
      ...ct,
      performance_metrics: {
        total_processing_ms: totalProcessingMs,
        meets_sla: !isBreached,
        sla_threshold_ms: resolvedThreshold,
        sla_breach_level: getBreachLevel(totalProcessingMs - resolvedThreshold),
        sla_breach_ms: isBreached ? (totalProcessingMs - resolvedThreshold) : 0,
        deadline_iso: new Date(deadlineTime).toISOString(),
        context: {
          tashkent_now: tashkentTimeStr,
          day_of_week: dayOfWeek,
          is_business_hours: isBusinessHours,
          applied_multiplier: multiplier,
          severity_used: severity
        }
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

const item = $input.first();
// FIX: Ensure we point to the correct path used in Phase 0/1
const ct = item.json.canonical_ticket || {};
const text = (ct.subject || '') + ' ' + (ct.body || '');
const textLower = text.toLowerCase();

if (!text.trim()) {
  throw new Error("LANGUAGE_ENGINE_ERROR: Empty input text");
}

const uzbekPatterns = [
  /\b(iltimos|rahmat|yordam|muammo|tizim|hisob|to'lov|ishlamayapti|shaxsiy|kabinet|tadbirkor)\b/i,
  /[o'|o’|g'|g’|sh|ch|q|h]/i // Common Uzbek specific characters/digraphs
];

const russianPatterns = [
  /\b(пожалуйста|спасибо|проблема|оплата|ошибка|доступ|кабинет|мерчант|вход|не|работает)\b/i,
  /[а-яё]/i // Cyrillic check
];

const englishPatterns = [
  /\b(please|help|issue|error|login|access|portal|merchant|unable|support|failed|denied)\b/i
];

let uzScore = uzbekPatterns.reduce((s, p) => s + (p.test(textLower) ? 1.5 : 0), 0);
let ruScore = russianPatterns.reduce((s, p) => s + (p.test(textLower) ? 1.5 : 0), 0);
let enScore = englishPatterns.reduce((s, p) => s + (p.test(textLower) ? 1.5 : 0), 0);

// Fallback: If no keywords match, check character sets
if (uzScore + ruScore + enScore === 0) {
  if (/[а-яё]/i.test(text)) ruScore = 1;
  else enScore = 1;
}

let detected = 'en';
let confidence = 0.5;

const maxScore = Math.max(uzScore, ruScore, enScore);

if (uzScore === maxScore) detected = 'uz';
else if (ruScore === maxScore) detected = 'ru';
else detected = 'en';

// Enterprise Confidence Calculation
