// PRODUCTION VALIDATOR (Logic Only - No External Modules)
const crypto = require('crypto');

// 1. INPUT SETUP
// Merge1 gave us the DB record (root) AND the Webhook (in .body)
const stored_record = $json; 
const approval_payload = $json.body;

console.log(`[VALIDATOR] Processing approval: ${stored_record.approval_id}`);

// 2. CHECK: DATA INTEGRITY
if (!approval_payload) {
  throw new Error('PAYLOAD_MISSING: No webhook body found in input');
}

// 3. CHECK: CONSUMED STATUS (Double Spend Protection)
if (stored_record.consumed !== false) {
  throw new Error(`APPROVAL_ALREADY_CONSUMED: This ticket was used on ${stored_record.consumed_at}`);
}

// 4. CHECK: STATE (Case Insensitive)
if (stored_record.state.toUpperCase() !== 'PENDING') {
  throw new Error(`INVALID_STATE: Expected PENDING, got ${stored_record.state}`);
}

// 5. CHECK: PREVIOUS HMAC VERIFICATION
// Instead of recalculating, we check the rigorous audit from the previous node
// This prevents "logic drift" between nodes
const previous_security_check = stored_record.security || {};

if (previous_security_check.is_authorized === true) {
   // PASSED
} else {
   // DETAILED ERROR REPORTING
   const hmac_status = stored_record.hmac_check || {};
   throw new Error(`SECURITY_VIOLATION: HMAC Mismatch. 
     Received: ${hmac_status.received}
     Calculated: ${hmac_status.calculated}
     (Ensure your HMAC Generator and Verifier use the EXACT same data string)`);
}

// 6. CHECK: EXPIRY
const now = new Date();
const expiresAt = new Date(stored_record.expires_at);
const isExpired = now > expiresAt;

// 7. SUCCESS OUTPUT
// We pass the crucial auditor details so Supabase can log WHO did it
return [{
  json: {
    valid: !isExpired,
    reason: isExpired ? "EXPIRED" : "OK",
    action: isExpired ? "REJECT_TRANSACTION" : "AUTHORIZE_TRANSACTION",

    // Identity & Audit Trail
    approval_id: stored_record.approval_id,
    trace_id: stored_record.trace_id,
    approver_id: approval_payload.approver_id,     // <--- Added this
    approver_role: approval_payload.approver_role, // <--- Added this

    // Decision Details
    decision: approval_payload.decision,
    approval_timestamp: approval_payload.approval_timestamp, // <--- Added this

    meta: {
      timestamp: now.toISOString(),
      validator: "5.0-logic-gate",
      expires_at: stored_record.expires_at
    }
  }
}];

const crypto = require('crypto');

// 1. Pull dynamic data from the previous node
const previousNodeData = $('Create a row1').item.json;
const BANK_HMAC_SECRET = $vars.BANK_HMAC_SECRET;

if (!BANK_HMAC_SECRET) throw new Error('BANK_HMAC_SECRET not configured');

// 2. Map Values
const approval_id = previousNodeData.approval_id;
const advisory_hash = previousNodeData.advisory_hash;
const trace_id = previousNodeData.trace_id;

// 3. Execution Values
const approver_id = "system_bot_001";
const approval_timestamp = new Date().toISOString();
const decision = "APPROVED";

// 4. Calculate HMAC (SANITIZED VERSION)
const hmacParts = [
  approval_id,
  advisory_hash,
  trace_id,
  approver_id,
  approval_timestamp,
  decision
];

// matches the Verifier exactly
const hmacData = hmacParts.map(val => String(val).trim()).join(':');

const hmac = crypto.createHmac('sha256', BANK_HMAC_SECRET)
  .update(hmacData)
  .digest('hex');

// 5. Generate CURL
const curlCommand = `curl -X POST "https://notheroeb.app.n8n.cloud/webhook-test/0c2a1910-9883-48cd-8d52-301d6476a209" -H "Content-Type: application/json" -d '{"approval_id":"${approval_id}","decision":"${decision}","approver_id":"${approver_id}","approver_role":"risk_officer","approval_timestamp":"${approval_timestamp}","advisory_hash":"${advisory_hash}","approval_hmac":"${hmac}","trace_id":"${trace_id}"}'`;

return {
  hmac,
  curlCommand,
  debug_trace_id: trace_id
};

// ENTERPRISE BLOCK 3 GUARD - REFACTORED FOR NESTED JSON
const items = $input.all();
const results = [];

for (const item of items) {
  // Use a reference to the ticket to keep code clean
  const ticket = item.json.canonical_ticket || {};
  const metrics = ticket.business_impact?.metrics || {};

  const validationErrors = [];

  // 1. Check for valid calculation (using the actual path in your JSON)
  const aiCost = metrics.ai_cost_uzs;
  if (aiCost === undefined || aiCost === null || isNaN(aiCost)) {
    validationErrors.push("Calculation Error: ai_cost_uzs is invalid.");
  }

  // 2. Business Logic Guard (Check SLA metrics)
  const slaStatus = ticket.performance_metrics?.meets_sla;
  if (slaStatus === undefined) {
    validationErrors.push("Logic Error: SLA status missing from performance_metrics.");
  }

  // 3. Schema Check (Required for Forensic Logging)
  // Maps to your JSON: trace_id, category (as service_name), and ai_cost
  if (!ticket.trace_id || ticket.trace_id === "N/A") {
    validationErrors.push("Schema Error: Missing or invalid trace_id");
  }

  if (!ticket.category) {
    validationErrors.push("Schema Error: Missing category (service_name)");
  }

  results.push({
    json: {
      ...item.json, // Keep original data
      block3_passed: validationErrors.length === 0,
      block3_report: validationErrors.join(' | ') || "Success"
    }
  });
}

return results;

// FORMAT ERROR FOR INCIDENT REPORTING
const item = $input.item.json;

return {
  incident_report: `🚨 BLOCK 3 VALIDATION FAILED
  ---------------------------
  TRACE ID: ${item.canonical_ticket.trace_id}
  REPORT: ${item.block3_report}
  TIMESTAMP: ${new Date().toISOString()}
  ENV: Development
  ---------------------------
  Action: Workflow Halted to prevent data corruption.`
};

// NODE: Advisory Recovery & Fallback
const items = $input.all();
const output = [];

for (const item of items) {
    let finalItem = { ...item.json };

    finalItem._execution_metadata = finalItem._execution_metadata || {};

    // Check if the previous node returned an error
    if (item.json.error || !item.json.choices) {
        console.log("LLM Failure Detected. Activating Deterministic Fallback...");

        // ENTERPRISE FALLBACK LOGIC
        const ct = item.json.canonical_ticket || {};
        const intent = ct.classification?.intent || 'unknown';

        finalItem.advisory_output = {
            explanation: `Automated detection of ${intent.replace('_', ' ')}. System encountered a 403 Forbidden error at the merchant portal.`,
            suggested_next_steps: [
                "Verify user permissions in the merchant database",
                "Check if the IP address is blacklisted in the Uzbekistan region",
                "Review WAF logs for blocked POST requests"
            ],
            draft_customer_response: "Hello! We've identified a 403 access issue with your account. Our technical team is investigating your permissions and will update you shortly.",
            advisory_note: "LLM_FALLBACK_ACTIVE: Advisory generated via deterministic rules due to provider timeout or auth error.",
            confidence_disclaimer: "Deterministic fallback - High reliability"
        };

        finalItem._execution_metadata.fallback_triggered = true;
    } else {
        // LLM Success - Extract the JSON from the assistant message
        try {
            const rawContent = item.json.choices[0].message.content;
            finalItem.advisory_output = JSON.parse(rawContent);
            finalItem._execution_metadata.fallback_triggered = false;
        } catch (e) {
            finalItem.advisory_output = { error: "Failed to parse LLM response" };
        }
    }

    output.push({ json: finalItem });
}

return output;

