const crypto = require('crypto');

// ---------- 1. DATA ACQUISITION ----------
// Since we used a Merge node, all data is in the first item
const data = $input.item.json;

// Extract webhook details from the 'body' property created by the Wait node
const webhook = data.body;

if (!webhook || !webhook.approval_hmac) {
  throw new Error("CRITICAL: Webhook body or HMAC not found in merged data.");
}

// ---------- 2. SECRET ----------
const BANK_HMAC_SECRET = $vars.BANK_HMAC_SECRET;
if (!BANK_HMAC_SECRET) {
  throw new Error('BANK_HMAC_SECRET not configured in n8n Variables');
}

// ---------- 3. HMAC RECONSTRUCTION ----------
// We use the exact same fields and order as the Generator
const hmacData = [
  webhook.approval_id,
  data.advisory_hash,    // Source of truth from DB
  webhook.trace_id,
  webhook.approver_id,
  webhook.approval_timestamp,
  webhook.decision
].map(val => String(val).trim()).join(':');

const calculatedHmac = crypto
  .createHmac('sha256', BANK_HMAC_SECRET)
  .update(hmacData, 'utf8')
  .digest('hex');

// ---------- 4. VALIDATION LOGIC ----------
const hmacMatches = (calculatedHmac === webhook.approval_hmac);
const isExpired = new Date() > new Date(data.expires_at);
const isAlreadyConsumed = data.consumed === true;

// Full authorization check
const authorized = hmacMatches && !isExpired && !isAlreadyConsumed;

// ---------- 5. OUTPUT ----------
return [
  {
    json: {
      // Pass through all original DB fields
      ...data,
      // Add verification results
      hmac_check: {
        received: webhook.approval_hmac,
        calculated: calculatedHmac,
        match: hmacMatches
      },
      security: {
        is_authorized: authorized,
        is_expired: isExpired,
        is_duplicate: isAlreadyConsumed
      },
      // Final Audit Label for the next node
      audit_label: authorized ? 'CRYPTO_VERIFIED' : 'VERIFICATION_FAILED'
    }
  }
];

const crypto = require('crypto');

// Parse the validated_approval string from the previous node
const input = $json;
const validated = JSON.parse(input.validated_approval);

// 1. Generate the Idempotence Key (Unique fingerprint for this dispatch)
const approved_channel = input.approval_request.selected_channel;
const idempotence_key = crypto.createHash('sha256')
  .update(`${validated.approval_id}:${approved_channel}:${validated.trace_id}:${input.advisory_hash}`)
  .digest('hex');

// 2. Prepare the payload for the Supabase Lock node
return {
  idempotence_key,
  approved_channel,
  approval_id: validated.approval_id,
  trace_id: validated.trace_id,
  advisory_hash: input.advisory_hash,
  decision: validated.decision,
  // Pass through the original input to keep data flowing
  parent_data: input 
};

